     2→import { DecoratorNode, COMMAND_PRIORITY_EDITOR, createCommand } from "lexical";
     3→import ImageComponent from "../ImageComponent";
     4→import ResizableImageComponent from "../ResizableImageComponent";
     5→
     6→export const INSERT_IMAGE_COMMAND = createCommand('INSERT_IMAGE_COMMAND');
     7→
     8→export default class ImageNode extends DecoratorNode {
     9→  static getType() {
    10→    return "image";
    11→  }
    12→
    13→  static clone(node) {
    14→    return new ImageNode(
    15→      node.__src,
    16→      node.__width,
    17→      node.__height,
    18→      node.__loading,
    19→      node.__key,
    20→    );
    21→  }
    22→
    23→  constructor(src, width = 400, height = 300, loading = false, key) {
    24→    super(key);
    25→    this.__src = src;
    26→    this.__width = width;
    27→    this.__height = height;
    28→    this.__loading = loading;
    29→  }
    30→
    31→  createDOM() {
    32→    const div = document.createElement("div");
    33→    div.className = 'image-container'
    34→    return div;
    35→  }
    36→
    37→  updateDOM() {
    38→    return false;
    39→  }
    40→
    41→  exportJSON() {
    42→    return {
    43→      type: "image",
    44→      version: 1,
    45→      src: this.__src,
    46→      width: this.__width,
    47→      height: this.__height,
    48→    };
    49→  }
    50→
    51→  static importJSON(serializedNode) {
    52→    const { src, width, height, filePath } = serializedNode;
    53→    return $createImageNode(src, width, height); 
    54→  }
    55→
    56→  // update dimensions when user resizes
    57→  setWidthAndHeight(width, height) {
    58→    const writable = this.getWritable();
    59→    writable.__width = width;
    60→    writable.__height = height;
    61→  }
    62→
    63→  setSrcAndLoading(src, loading) {
    64→    const writable = this.getWritable();
    65→    writable.__src = src;
    66→    writable.__loading = loading;
    67→  }
    68→
    69→  getWidth() {
    70→    return this.__width;
    71→  }
    72→
    73→  getHeight() {
    74→    return this.__height;
    75→  }
    76→
    77→  decorate(editor) {
    78→    const src = this.__src;
    79→    const nodeKey = this.getKey();
    80→    const width = this.__width;
    81→    const height = this.__height;
    82→    const loading = this.__loading;
    83→    const isEditable = editor.isEditable();
    84→    return <ResizableImageComponent src={src} nodeKey={nodeKey} width={width} height={height} loading={loading} isEditable={isEditable}/>;
    85→  }
    86→}
    87→
    88→//helper function to create ImageNode
    89→export function $createImageNode(src, width = 400, height = 300, loading = false) {
    90→  return new ImageNode(src, width, height, loading);
    91→}
