     1→import { useState, useRef, useEffect } from 'react';
     2→import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
     3→import { $getNodeByKey } from 'lexical';
     4→import { deleteJournalImage } from '../../../../API/Api';
     5→import { useAuth } from '../../../Context/useAuth';
     6→import { AnimatePresence, motion, scale } from 'framer-motion';
     7→
     8→const ResizableImageComponent = ({ src ,nodeKey, width, height, loading = false, isEditable = true }) => {
     9→  const [editor] = useLexicalComposerContext();
    10→  const [isResizing, setIsResizing] = useState(false);
    11→  const [currentWidth, setCurrentWidth] = useState(width);
    12→  const [currentHeight, setCurrentHeight] = useState(height);
    13→  const [isSelected, setIsSelected] = useState(false);
    14→  const imageRef = useRef(null);
    15→  const startPosRef = useRef({ x: 0, y: 0, width: 0, height: 0 });
    16→
    17→  const [viewImage, setViewImage] = useState(false);
    18→
    19→  const{session} = useAuth();
    20→
    21→  //handle delete image from the editor
    22→  const deleteImgSync = async(imgUrl) => {
    23→    try {
    24→      const message = await deleteJournalImage(session?.access_token, imgUrl);
    25→      if(message){
    26→        console.log(message.message)
    27→      }
    28→    } catch (error) {
    29→      console.error("Failed to delete image from storage:", error);
    30→    }
    31→  }
    32→  const handleDelete = async(e) =>{
    33→    e.stopPropagation();
    34→    let img_url = ''
    35→    const data = {
    36→      filepath: []
    37→    }
    38→    editor.update(() =>{
    39→        const node = editor.getEditorState()._nodeMap.get(nodeKey);
    40→        if(!node || !node.__src) {
    41→          throw new Error('Node not found or missing source')
    42→        }
    43→        img_url = node.__src
    44→        node.remove();
    45→    });
    46→
    47→    //only proceed if node was removed and img_url is set
    48→    if(img_url){
    49→      data.filepath.push(img_url)
    50→      await deleteImgSync(data.filepath);
    51→    }
    52→  }
    53→
    54→  // handle mouse down on resize handle
    55→  const handleMouseDown = (e, corner) => {
    56→    // e.preventDefault();
    57→    e.stopPropagation();
    58→    
    59→    const isTouchStart = e.type === 'touchstart';
    60→    const clientX = isTouchStart ? e.touches[0].clientX : e.clientX;
    61→    const clientY = isTouchStart ? e.touches[0].clientY : e.clientY;
    62→    
    63→    setIsResizing(true);
    64→    startPosRef.current = {
    65→      x: clientX,
    66→      y: clientY,
    67→      width: currentWidth || 300,
    68→      height: currentHeight || 200,
    69→    };
    70→
    71→    const handleMouseMove = (moveEvent) => {
    72→        const isTouchMove = moveEvent.type === 'touchmove'
    73→        const moveX = isTouchMove ? moveEvent.touches[0].clientX : moveEvent.clientX;
    74→        const moveY = isTouchMove ? moveEvent.touches[0].clientY : moveEvent.clientY;
    75→
    76→        const deltaX = (moveX - startPosRef.current.x) / 8;
    77→        const deltaY = (moveY - startPosRef.current.y) / 8;
    78→
    79→        let newWidth, newHeight;
    80→
    81→        if (corner === 'se') {
    82→            // southeast corner - resize proportionally
    83→            const aspectRatio =startPosRef.current.width / startPosRef.current.height;
    84→            newWidth = Math.max(100, startPosRef.current.width + deltaX);
    85→            newHeight = newWidth / aspectRatio;
    86→        } else if (corner === 'e') {
    87→            // east side - resize width only
    88→            newWidth = Math.max(100, startPosRef.current.width + deltaX);
    89→            newHeight = currentHeight;
    90→        } else if (corner === 's') {
    91→            // south side - resize height only
    92→            newWidth = currentWidth;
    93→            newHeight = Math.max(100, startPosRef.current.height + deltaY);
    94→        } else if(corner === 'ne') {
    95→            // northeast corner - resize proportionally
    96→            const aspectRatio = startPosRef.current.width / startPosRef.current.height;
    97→            newWidth = Math.max(100, startPosRef.current.width + deltaX)
    98→            newHeight = newWidth / aspectRatio
    99→        } else if (corner === 'sw') {
   100→            // southwest corner - resize proportionally
   101→            const aspectRatio = startPosRef.current.width / startPosRef.current.height;
   102→            newWidth = Math.max(100, startPosRef.current.width - deltaX)
   103→            newHeight = newWidth / aspectRatio
   104→        } else if (corner === 'nw') {
   105→            // northhwest corner - resize proportionally
   106→            const aspectRatio = startPosRef.current.width / startPosRef.current.height;
   107→            newWidth = Math.max(100, startPosRef.current.width - deltaX)
   108→            newHeight = newWidth / aspectRatio
   109→        }  else if(corner === 'n') {
   110→            // south side - resize height only
   111→            newWidth = currentWidth;
   112→            newHeight = Math.max(100, startPosRef.current.height - deltaY);
   113→        }
   114→
   115→        const roundedWidth = Math.round(newWidth);
   116→        const roundedHeight = Math.round(newHeight);
   117→
   118→        setCurrentWidth(roundedWidth);
   119→        setCurrentHeight(roundedHeight);
   120→        startPosRef.current.width = roundedWidth;
   121→        startPosRef.current.height = roundedHeight;
   122→    };
   123→    
   124→    const handleMouseUp = () => {
   125→        setIsResizing(false);
   126→
   127→        const finalWidth = startPosRef.current.width;
   128→        const finalHeight = startPosRef.current.height;
   129→
   130→        // console.log(`Saving: ${finalWidth}x${finalHeight}`);//for debugging
   131→      
   132→        // update the Lexical node with new dimensions
   133→        editor.update(() => {
   134→            const node = $getNodeByKey(nodeKey);
   135→            if (node && typeof node.setWidthAndHeight === 'function') {
   136→                node.setWidthAndHeight(finalWidth, finalHeight);
   137→            }
   138→        }, {
   139→                onUpdate: () => {
   140→                //forcing a statechange so if user resize the image it will update the editorstate
   141→                editor.update(() =>{
   142→                //empty because i only used this for triggering the OnChangePlugin
   143→                    })
   144→                }
   145→            }
   146→        );
   147→
   148→        //remove all listeners after mouse up
   149→        document.removeEventListener('touchmove', handleMouseMove)
   150→        document.removeEventListener('mousemove', handleMouseMove);
   151→        document.removeEventListener('mouseup', handleMouseUp);
   152→        document.removeEventListener('touchend', handleMouseUp)
   153→    };
   154→
   155→    //add all event listerner after mouse down or mouse hold click 
   156→    document.addEventListener('touchmove', handleMouseMove, {passive: false})
   157→    document.addEventListener('mousemove', handleMouseMove);
   158→    document.addEventListener('mouseup', handleMouseUp);
   159→    document.addEventListener('touchend', handleMouseUp)
   160→};
   161→
   162→
   163→  // handle image click for selection
   164→  const handleImageClick = () => {
   165→    setIsSelected(!isSelected);
   166→  };
   167→
   168→  //handle image  click for view
   169→  const handleViewImage = () => {
   170→    // console.log('view img')
   171→    if(!isEditable){
   172→      setViewImage(true)
   173→    } else {
   174→      return
   175→    }
   176→    
   177→  }
   178→
   179→  // click outside to deselect
   180→  useEffect(() => {
   181→    const handleClickOutside = (e) => {
   182→      if (imageRef.current && !imageRef.current.contains(e.target)) {
   183→        setIsSelected(false);
   184→      }
   185→    };
   186→
   187→    document.addEventListener('mousedown', handleClickOutside);
   188→    return () => document.removeEventListener('mousedown', handleClickOutside);
   189→  }, []);
   190→
   191→  return (
   192→    <>
   193→    {viewImage && (
   194→      <img onClick={() => setViewImage(!viewImage)} className='image-view' src={src} alt="view-image" />
   195→    )}
   196→
   197→    <div
   198→    className='image-wrapper'
   199→      ref={imageRef}
   200→      style={{
   201→        cursor: isResizing ? 'nwse-resize' : 'pointer',
   202→      }}
   203→      onClick={isEditable ? handleImageClick : handleViewImage}
   204→    >
   205→   
   206→      <AnimatePresence>
   207→      <motion.img
   208→        initial={{opacity: 0}}
   209→        animate={{opacity: 1, transition: {type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
   210→        exit={{ opacity: 0, y: -20,
   211→          transition: { 
   212→            duration: 0.2,
   213→            ease: "easeOut"
   214→          }
   215→        }}
   216→
   217→        src={src}
   218→        alt="content"
   219→        style={{
   220→          borderRadius: '5px',
   221→          width: `${currentWidth}px`,
   222→          height: `${currentHeight}px`,
   223→          display: 'block',
   224→          border: isSelected ? '1px solid rgba(153, 200, 255, 0.99)' : '2px solid transparent',
   225→          userSelect: 'none',
   226→        }}
   227→        draggable={false}
   228→        onClick={() => handleViewImage()}
   229→        className='image-content'
   230→      />
   231→      </AnimatePresence>
   232→
   233→      {loading && (
   234→        <div className="image-loading-overlay">
   235→          <div className="image-loading-spinner" />
   236→        </div>
   237→      )}
   238→
   239→      {isEditable && (
   240→      <div onClick={(e) => handleDelete(e)} className='image-delete'>
   241→        <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="#FFFFFF"><path d="m256-200-56-56 224-224-224-224 56-56 224 224 224-224 56 56-224 224 224 224-56 56-224-224-224 224Z"/></svg>
   242→      </div>
   243→      )}
   244→
   245→      {isSelected && isEditable &&(
   246→        <>
   247→          {/* southeast corner handle - proportional resize */}
   248→          <div
   249→            onMouseDown={(e) => handleMouseDown(e, 'se')}
   250→            onTouchStart={(e) => handleMouseDown(e, 'se')}
   251→            className='southeast-side-handle'
   252→          />
   253→
   254→          {/* southwest corner handle - proportional resize */}
   255→          <div
   256→            onMouseDown={(e) => handleMouseDown(e, 'sw')}
   257→            onTouchStart={(e) => handleMouseDown(e, 'sw')} 
   258→            className='southwest-side-handle'
   259→          />
   260→
   261→          {/* northeast corner handle - proportional resize */}
   262→          <div
   263→            onMouseDown={(e) => handleMouseDown(e, 'ne')}
   264→            onTouchStart={(e) => handleMouseDown(e, 'ne')} 
   265→            className='northeast-side-handle'
   266→          />
   267→
   268→          {/* northwest corner handle - proportional resize */}
   269→          <div
   270→            onMouseDown={(e) => handleMouseDown(e, 'nw')}
   271→            onTouchStart={(e) => handleMouseDown(e, 'nw')} 
   272→            className='northwest-side-handle'
   273→          />
   274→
   275→          {/* east side handle - width only */}
   276→          <div
   277→            onMouseDown={(e) => handleMouseDown(e, 'e')}
   278→            onTouchStart={(e) => handleMouseDown(e, 'e')} 
   279→            className='east-side-handle'
   280→          />
   281→
   282→          {/* south side handle - height only */}
   283→          <div
   284→            onMouseDown={(e) => handleMouseDown(e, 's')}
   285→            onTouchStart={(e) => handleMouseDown(e, 's')} 
   286→            className='south-side-handle'
   287→          />
   288→
   289→           {/* north side handle - height only */}
   290→          <div
   291→            onMouseDown={(e) => handleMouseDown(e, 'n')}
   292→            onTouchStart={(e) => handleMouseDown(e, 'n')} 
   293→            className='north-side-handle'
   294→          />
   295→
   296→          {/* dimensions display */}
   297→          <div
   298→          className='dimension-display'
   299→          >
   300→            {currentWidth} × {currentHeight}
   301→          </div>
   302→        </>
   303→      )}
   304→    </div>
   305→    </>
   306→  );
   307→}
   308→export default ResizableImageComponent;

